     6→/// A pipeline of preprocessing steps to be applied sequentially
     7→#[derive(Debug)]
     8→pub struct PreprocessPipeline {
     9→    steps: Vec<Box<dyn Preprocessor>>,
    10→    cache: HashMap<String, Matrix>,
    11→    config: PreprocessConfig,
    12→}
    13→
    14→impl Clone for PreprocessPipeline {
    15→    fn clone(&self) -> Self {
    16→        Self {
    17→            steps: self.steps.iter().map(|s| s.clone_box()).collect(),
    18→            cache: self.cache.clone(),
    19→            config: self.config.clone(),
    20→        }
    21→    }
    22→}
    23→
    24→impl PreprocessPipeline {
    25→    /// Create a new empty pipeline
    26→    pub fn new() -> Self {
    27→        Self {
    28→            steps: Vec::new(),
    29→            cache: HashMap::new(),
    30→            config: PreprocessConfig::default(),
    31→        }
    32→    }
    33→    
    34→    /// Create a pipeline with specific configuration
    35→    pub fn with_config(config: PreprocessConfig) -> Self {
    36→        Self {
    37→            steps: Vec::new(),
    38→            cache: HashMap::new(),
    39→            config,
    40→        }
    41→    }
    42→    
    43→    /// Add a preprocessing step to the pipeline
    44→    pub fn add_step(mut self, step: Box<dyn Preprocessor>) -> Self {
    45→        self.steps.push(step);
    46→        self
    47→    }
    48→    
    49→    /// Get the number of steps in the pipeline
    50→    pub fn len(&self) -> usize {
    51→        self.steps.len()
    52→    }
    53→    
    54→    /// Check if the pipeline is empty
    55→    pub fn is_empty(&self) -> bool {
    56→        self.steps.is_empty()
    57→    }
    58→    
    59→    /// Clear the cache
    60→    pub fn clear_cache(&mut self) {
    61→        self.cache.clear();
    62→    }
    63→    
    64→    /// Get a reference to the steps
    65→    pub fn steps(&self) -> &[Box<dyn Preprocessor>] {
    66→        &self.steps
    67→    }
    68→    
    69→    /// Get a mutable reference to the steps
    70→    pub fn steps_mut(&mut self) -> &mut Vec<Box<dyn Preprocessor>> {
    71→        &mut self.steps
    72→    }
    73→}
    74→
    75→impl Default for PreprocessPipeline {
    76→    fn default() -> Self {
