    81→impl Preprocessor for PreprocessPipeline {
    82→    fn fit(&mut self, data: &Matrix) -> Result<(), MultivariousError> {
    83→        let mut current = data.clone();
    84→        
    85→        for step in &mut self.steps {
    86→            step.fit(&current)?;
    87→            current = step.transform(&current)?;
    88→        }
    89→        
    90→        Ok(())
    91→    }
    92→    
    93→    fn transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
    94→        let mut current = data.clone();
    95→        
    96→        for step in &self.steps {
    97→            current = step.transform(&current)?;
    98→        }
    99→        
   100→        Ok(current)
   101→    }
   102→    
   103→    fn inverse_transform(&self, data: &Matrix) -> Result<Matrix, MultivariousError> {
   104→        let mut current = data.clone();
   105→        
   106→        // Apply inverse transforms in reverse order
   107→        for step in self.steps.iter().rev() {
   108→            current = step.inverse_transform(&current)?;
   109→        }
   110→        
   111→        Ok(current)
   112→    }
   113→    
   114→    fn is_fitted(&self) -> bool {
   115→        self.steps.iter().all(|step| step.is_fitted())
   116→    }
   117→    
   118→    fn name(&self) -> &str {
   119→        "PreprocessPipeline"
   120→    }
   121→    
   122→    fn clone_box(&self) -> Box<dyn Preprocessor> {
   123→        Box::new(self.clone())
   124→    }
   125→}
