//! Block management structures for multiblock datasets

use crate::common_types::Matrix;
use crate::errors::MultivariousError;
use serde::{Deserialize, Serialize};
use std::collections::HashMap;

/// Information about a single block in a multiblock dataset
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct BlockInfo {
    /// Name/identifier for the block
    pub name: String,
    /// Starting column index in the concatenated matrix
    pub start_col: usize,
    /// Number of columns in this block
    pub n_cols: usize,
    /// Optional weight for this block in consensus analysis
    pub weight: f64,
    /// Optional metadata about the block
    pub metadata: Option<HashMap<String, String>>,
}

impl BlockInfo {
    /// Create a new block info
    pub fn new(name: String, start_col: usize, n_cols: usize) -> Self {
        Self {
            name,
            start_col,
            n_cols,
            weight: 1.0,
            metadata: None,
        }
    }

    /// Set the weight for this block
    pub fn with_weight(mut self, weight: f64) -> Self {
        self.weight = weight;
        self
    }

    /// Add metadata to the block
    pub fn with_metadata(mut self, key: String, value: String) -> Self {
        if self.metadata.is_none() {
            self.metadata = Some(HashMap::new());
        }
        if let Some(ref mut metadata) = self.metadata {
            metadata.insert(key, value);
        }
        self
    }

    /// Get the ending column index (exclusive)
    pub fn end_col(&self) -> usize {
        self.start_col + self.n_cols
    }

    /// Check if a column index is within this block
    pub fn contains_column(&self, col_idx: usize) -> bool {
        col_idx >= self.start_col && col_idx < self.end_col()
    }
}

/// A single block of data with its associated information
#[derive(Debug, Clone)]
pub struct Block {
    /// Block metadata
    pub info: BlockInfo,
    /// The data matrix for this block
    pub data: Matrix,
}

impl Block {
    /// Create a new block
    pub fn new(info: BlockInfo, data: Matrix) -> Result<Self, MultivariousError> {
        if data.ncols() != info.n_cols {
            return Err(MultivariousError::DimensionMismatch {
                expected: format!("{} columns", info.n_cols),
                actual: format!("{} columns", data.ncols()),
            });
        }

        Ok(Self { info, data })
    }

    /// Get the number of rows
    pub fn n_rows(&self) -> usize {
        self.data.nrows()
    }

    /// Get the number of columns
    pub fn n_cols(&self) -> usize {
        self.data.ncols()
    }

    /// Get a reference to the data
    pub fn data(&self) -> &Matrix {
        &self.data
    }

    /// Get a mutable reference to the data
    pub fn data_mut(&mut self) -> &mut Matrix {
        &mut self.data
    }
}

/// Indices for accessing blocks in a concatenated matrix
#[derive(Debug, Clone)]
pub struct BlockIndices {
    /// Mapping from block name to column range
    indices: HashMap<String, (usize, usize)>,
    /// Total number of columns across all blocks
    total_cols: usize,
    /// Order of blocks
    block_order: Vec<String>,
}

impl BlockIndices {
    /// Create new block indices from block information
    pub fn from_blocks(blocks: &[BlockInfo]) -> Self {
        let mut indices = HashMap::new();
        let mut block_order = Vec::new();
        let mut total_cols = 0;

        for block in blocks {
            indices.insert(
                block.name.clone(),
                (block.start_col, block.end_col())
            );
            block_order.push(block.name.clone());
            total_cols = total_cols.max(block.end_col());
        }

        Self {
            indices,
            total_cols,
            block_order,
        }
    }

    /// Get the column range for a block by name
    pub fn get_range(&self, block_name: &str) -> Option<(usize, usize)> {
        self.indices.get(block_name).copied()
    }

    /// Get all block names in order
    pub fn block_names(&self) -> &[String] {
        &self.block_order
    }

    /// Get the total number of columns
    pub fn total_columns(&self) -> usize {
        self.total_cols
    }

    /// Check if a block exists
    pub fn contains_block(&self, block_name: &str) -> bool {
        self.indices.contains_key(block_name)
    }

    /// Get the number of blocks
    pub fn n_blocks(&self) -> usize {
        self.indices.len()
    }
}

/// A multiblock dataset containing multiple blocks of data
#[derive(Debug, Clone)]
pub struct BlockDataset {
    /// Individual blocks
    blocks: Vec<Block>,
    /// Block indices for the concatenated representation
    indices: BlockIndices,
    /// Number of observations (rows)
    n_obs: usize,
}

impl BlockDataset {
    /// Create a new block dataset from individual blocks
    pub fn new(blocks: Vec<Block>) -> Result<Self, MultivariousError> {
        if blocks.is_empty() {
            return Err(MultivariousError::InvalidParameter {
                name: "blocks".to_string(),
                reason: "At least one block is required".to_string(),
            });
        }

        // Check that all blocks have the same number of rows
        let n_obs = blocks[0].n_rows();
        for (i, block) in blocks.iter().enumerate().skip(1) {
            if block.n_rows() != n_obs {
                return Err(MultivariousError::DimensionMismatch {
                    expected: format!("{} rows (from first block)", n_obs),
                    actual: format!("{} rows in block '{}'", block.n_rows(), block.info.name),
                });
            }
        }

        // Update block info with correct column indices
        let mut current_col = 0;
        let mut updated_blocks = Vec::new();

        for mut block in blocks {
            block.info.start_col = current_col;
            current_col += block.info.n_cols;
            updated_blocks.push(block);
        }

        let block_infos: Vec<BlockInfo> = updated_blocks.iter()
            .map(|b| b.info.clone())
            .collect();
        let indices = BlockIndices::from_blocks(&block_infos);

        Ok(Self {
            blocks: updated_blocks,
            indices,
            n_obs,
        })
    }

    /// Create a block dataset from a concatenated matrix and block information
    pub fn from_concatenated(data: &Matrix, block_infos: Vec<BlockInfo>) -> Result<Self, MultivariousError> {
        let mut blocks = Vec::new();

        for info in block_infos {
            if info.end_col() > data.ncols() {
                return Err(MultivariousError::InvalidParameter {
                    name: "block_infos".to_string(),
                    reason: format!("Block '{}' extends beyond matrix columns", info.name),
                });
            }

            let block_data = data.slice(ndarray::s![.., info.start_col..info.end_col()]).to_owned();
            blocks.push(Block::new(info, block_data)?);
        }

        Self::new(blocks)
    }

    /// Get the number of blocks
    pub fn n_blocks(&self) -> usize {
        self.blocks.len()
    }

    /// Get the number of observations
    pub fn n_obs(&self) -> usize {
        self.n_obs
    }

    /// Get the total number of columns across all blocks
    pub fn n_cols(&self) -> usize {
        self.indices.total_columns()
    }

    /// Get a reference to a block by index
    pub fn get_block(&self, index: usize) -> Option<&Block> {
        self.blocks.get(index)
    }

    /// Get a reference to a block by name
    pub fn get_block_by_name(&self, name: &str) -> Option<&Block> {
        self.blocks.iter().find(|b| b.info.name == name)
    }

    /// Get a mutable reference to a block by index
    pub fn get_block_mut(&mut self, index: usize) -> Option<&mut Block> {
        self.blocks.get_mut(index)
    }

    /// Get a mutable reference to a block by name
    pub fn get_block_by_name_mut(&mut self, name: &str) -> Option<&mut Block> {
        self.blocks.iter_mut().find(|b| b.info.name == name)
    }

    /// Get all blocks
    pub fn blocks(&self) -> &[Block] {
        &self.blocks
    }

    /// Get mutable access to all blocks
    pub fn blocks_mut(&mut self) -> &mut Vec<Block> {
        &mut self.blocks
    }

    /// Get the block indices
    pub fn indices(&self) -> &BlockIndices {
        &self.indices
    }

    /// Concatenate all blocks into a single matrix
    pub fn to_concatenated(&self) -> Matrix {
        let mut result = Matrix::zeros((self.n_obs, self.n_cols()));

        for block in &self.blocks {
            let start = block.info.start_col;
            let end = block.info.end_col();
            result.slice_mut(ndarray::s![.., start..end]).assign(&block.data);
        }

        result
    }

    /// Create an iterator over blocks
    pub fn iter(&self) -> impl Iterator<Item = &Block> {
        self.blocks.iter()
    }

    /// Create a mutable iterator over blocks
    pub fn iter_mut(&mut self) -> impl Iterator<Item = &mut Block> {
        self.blocks.iter_mut()
    }

    /// Extract a subset of blocks by name
    pub fn subset(&self, block_names: &[String]) -> Result<Self, MultivariousError> {
        let mut subset_blocks = Vec::new();

        for name in block_names {
            if let Some(block) = self.get_block_by_name(name) {
                subset_blocks.push(block.clone());
            } else {
                return Err(MultivariousError::InvalidParameter {
                    name: "block_names".to_string(),
                    reason: format!("Block '{}' not found", name),
                });
            }
        }

        Self::new(subset_blocks)
    }

    /// Apply a function to each block
    pub fn map_blocks<F>(&self, f: F) -> Result<Self, MultivariousError>
    where
        F: Fn(&Block) -> Result<Matrix, MultivariousError>,
    {
        let mut new_blocks = Vec::new();

        for block in &self.blocks {
            let new_data = f(block)?;
            let new_block = Block::new(block.info.clone(), new_data)?;
            new_blocks.push(new_block);
        }

        Self::new(new_blocks)
    }
}

